// Helper: allocate a dummy 1-element array if length is 0, to avoid NULL map issues
static double * safe_double_alloc(double * ptr, long length)
{
	if( length > 0 ) return ptr;
	// return a dummy pointer - we allocate 1 element
	// We use a static dummy; since it's only used when length==0, no actual access occurs
	static double dummy_d = 0.0;
	return &dummy_d;
}

static int * safe_int_alloc(int * ptr, long length)
{
	if( length > 0 ) return ptr;
	static int dummy_i = 0;
	return &dummy_i;
}

