unsigned long long run_event_based_simulation_optimization_1(Inputs in, SimulationData SD, int mype)
{
	char * optimization_name = "Optimization 1 - Kernel splitting + full material & energy sort";

	if( 0 == mype) printf("Simulation Kernel:\"%s\"\n", optimization_name);

	size_t sz;
	size_t total_sz = 0;
	double start, stop;

	sz = in.lookups * sizeof(double);
	SD.p_energy_samples = (double *) malloc(sz);
	total_sz += sz;
	SD.length_p_energy_samples = in.lookups;

	sz = in.lookups * sizeof(int);
	SD.mat_samples = (int *) malloc(sz);
	total_sz += sz;
	SD.length_mat_samples = in.lookups;

	if( 0 == mype) printf("Allocated an additional %.0lf MB of data on GPU.\n", total_sz/1024.0/1024.0);

	// Sample Materials and Energies on CPU
	#pragma omp parallel for schedule(dynamic, 100)
	for( int i = 0; in.lookups > i; i++ )
	{
		uint64_t seed = STARTING_SEED;	
		seed = fast_forward_LCG(seed, 2*i);

		double p_energy = LCG_random_double(&seed);
		int mat         = pick_mat(&seed); 

		SD.p_energy_samples[i] = p_energy;
		SD.mat_samples[i] = mat;
	}
	if(0 == mype) printf("finished sampling...\n");

	// Sort by Material
	start = omp_get_wtime();
	quickSort_parallel_i_d(SD.mat_samples, SD.p_energy_samples, in.lookups, in.nthreads);
	stop = omp_get_wtime();
	if(0 == mype) printf("Material sort took %.3lf seconds\n", stop-start);

	// Sort by Energy
	start = omp_get_wtime();

	int num_samples_per_mat[12] = {0};
	for( int l = 0; in.lookups > l; l++ )
		num_samples_per_mat[ SD.mat_samples[l] ]++;

	int offsets[12] = {0};
	for( int mm = 1; 12 > mm; mm++ )
		offsets[mm] = offsets[mm-1] + num_samples_per_mat[mm-1];

	stop = omp_get_wtime();
	if(0 == mype) printf("Counting samples and offsets took %.3lf seconds\n", stop-start);
	start = stop;

	for( int mm = 0; 12 > mm; mm++ )
		quickSort_parallel_d_i(SD.p_energy_samples + offsets[mm], SD.mat_samples + offsets[mm], num_samples_per_mat[mm], in.nthreads);

	stop = omp_get_wtime();
	if(0 == mype) printf("Energy Sorts took %.3lf seconds\n", stop-start);

	// Perform lookups
	start = omp_get_wtime();

	unsigned long long verification = 0;

	long n_isotopes = in.n_isotopes;
	long n_gridpoints = in.n_gridpoints;
	int grid_type = in.grid_type;
	int hash_bins = in.hash_bins;
	int max_num_nucs = SD.max_num_nucs;

	int length_num_nucs = SD.length_num_nucs;
	int length_concs = SD.length_concs;
	int length_mats = SD.length_mats;
	long length_unionized_energy_array = (SD.length_unionized_energy_array > 0) ? SD.length_unionized_energy_array : 1;
	long length_index_grid = (SD.length_index_grid > 0) ? SD.length_index_grid : 1;
	int length_nuclide_grid = SD.length_nuclide_grid;
	int length_p_energy_samples = SD.length_p_energy_samples;
	int length_mat_samples = SD.length_mat_samples;

	int * num_nucs = SD.num_nucs;
	double * concs = SD.concs;
	int * mats = SD.mats;
	NuclideGridPoint * nuclide_grid = SD.nuclide_grid;
	double * p_energy_samples = SD.p_energy_samples;
	int * mat_samples = SD.mat_samples;

	double * unionized_energy_array = (SD.length_unionized_energy_array > 0) ? SD.unionized_energy_array : safe_double_alloc(NULL, 0);
	int * index_grid = (SD.length_index_grid > 0) ? SD.index_grid : safe_int_alloc(NULL, 0);

	#pragma omp target data \
		map(to: num_nucs[0:length_num_nucs]) \
		map(to: concs[0:length_concs]) \
		map(to: mats[0:length_mats]) \
		map(to: nuclide_grid[0:length_nuclide_grid]) \
		map(to: unionized_energy_array[0:length_unionized_energy_array]) \
		map(to: index_grid[0:length_index_grid]) \
		map(to: p_energy_samples[0:length_p_energy_samples]) \
		map(to: mat_samples[0:length_mat_samples])
	{
		int offset = 0;
		for( int m = 0; 12 > m; m++ )
		{
			int mat_offset = offset;
			int mat_count = num_samples_per_mat[m];

			if( mat_count > 0 )
			{
				#pragma omp target teams distribute parallel for \
					reduction(+:verification)
				for( int i = mat_offset; mat_offset + mat_count > i; i++)
				{
					double p_energy = p_energy_samples[i];
					int mat_val     = mat_samples[i]; 

					double macro_xs_vector[5] = {0};

					calculate_macro_xs(
							p_energy,
							mat_val,
							n_isotopes,
							n_gridpoints,
							num_nucs,
							concs,
							unionized_energy_array,
							index_grid,
							nuclide_grid,
							mats,
							macro_xs_vector,
							grid_type,
							hash_bins,
							max_num_nucs
							);

					double max = -1.0;
					int max_idx = 0;
					for(int j = 0; 5 > j; j++ )
					{
						if( max < macro_xs_vector[j] )
						{
							max = macro_xs_vector[j];
							max_idx = j;
						}
					}
					verification += (unsigned long long)(max_idx+1);
				}
			}
			offset += num_samples_per_mat[m];
		}
	}

	stop = omp_get_wtime();
	if(0 == mype) printf("XS Lookups took %.3lf seconds\n", stop-start);
	return verification;
}

